export default {
	data() {
		return {
			showBox: false,
			tabIndex: 0,
			scrollInto: '',
			tabBars: [],
			current: 0,
			styleType: 'text',
			activeColor: '#ff0000',
			contentType: '',
			carList: [], //车位
			storeList: [], //商铺
			houseData: [], //住宅和别墅
			originalHouseData: [], //住宅和别墅原始数据
			originalStoreData: [], //商铺原始数据
			storeTrue: [], //可选商铺数量
			carTrue: [], //可选车位数量
			houseTrue: [], //可选房产数量
			pc_id: '',
			cb_id: '',
			showBoxData: '',
			houseDetail:'',
			type:1,
			bname:''
		};
	},
	methods: {
		onLoad(options) {
			this.bid = options.bid;
			this.pname = options.pname;
			this.bname = options.bname;
			this.getTypeRooms();
			
		},
		ontabtap(e) {
			let index = e.target.dataset.current || e.currentTarget.dataset.current;
			this.tabIndex = index;
			this.type = this.tabBars[this.tabIndex].id;
			this.getChHouse();
		},
		changeRoom(item) {
			console.log('item: ' + JSON.stringify(item));
			if (item.buyed) {
				this.showBox = !this.showBox;
				this.showBoxData = item;
			} else {
				uni.showToast({
					icon: 'none',
					title: '房源已被选...'
				});
			}
		},
		getTypeRooms() {
			this.$api.customGettypecustomapi({}, res => {
				if (res.code == 1000) {
					this.tabBars = res.data;
					this.type = this.tabBars[this.tabIndex].id;
					this.getChHouse();
				}
			});
		},
		dealHouse() {
			let data = {
				pc_id: this.pc_id,
				cr_id: this.showBoxData.cr_id
			};
			return;
			uni.showLoading({
				title: '正在确认中...'
			});
			this.$api.chDeal(data, res => {
				uni.switchTab({
					url: '/pages/user/user'
				});
			});
		},

		getChHouse() {
			let data = {
				bid: this.bid,
				type:this.type
			};
			uni.showLoading({
				title: '正在获取房源数据...'
			});
			this.$api.GetRoomslistcustomapi(data, res => {
				
				if (res.code == 1000) {
					this.houseDetail = res.statistics;
					this.houseData = res.data;
				}
			});
		},

		initHouseData(data) {
			let unitAry = {};
			let floorAry = [];
			let unitFloorAry = [];
			let unitFloorAry1 = [];
			//单元->楼层->门户
			for (let a = 0, len = data.length; a < len; a++) {
				let unit = data[a].unit;
				let floor = data[a].floor;
				let unitFloor = unit + '-' + floor;
				if (!unitAry.hasOwnProperty(unit)) {
					unitAry[unit] = {};
					unitAry[unit]['unit'] = '';
					unitAry[unit]['unitList'] = {};
					unitAry[unit]['unitList'] = {};
				}
				//单元楼对象
				unitAry[unit]['unit'] = unit;
				//
				if (!unitFloorAry.hasOwnProperty(unitFloor)) {
					unitFloorAry[unitFloor] = {};
					unitFloorAry[unitFloor]['floor'] = '';
					unitFloorAry[unitFloor]['floorList'] = [];
				}
				unitFloorAry[unitFloor]['floor'] = floor;
				unitFloorAry[unitFloor]['floorList'].push(data[a]);
				unitAry[unit]['unitList'][floor] = unitFloorAry[unitFloor];
			}
			this.houseData = unitAry;
		},
		initStoreData(data) {
			let unitAry = [];
			let unitFloorAry = [];
			let unitFloorAry1 = [];
			//单元->楼层->门户
			for (let a = 0, len = data.length; a < len; a++) {
				let floor = data[a].floor;
				if (!unitFloorAry.hasOwnProperty(floor)) {
					unitFloorAry[floor] = {};
					unitFloorAry[floor]['floor'] = '';
					unitFloorAry[floor]['floorList'] = [];
				}
				unitFloorAry[floor]['floor'] = floor;
				unitFloorAry[floor]['floorList'].push(data[a]);
				unitAry[floor] = unitFloorAry[floor];
			}
			this.storeList = unitAry;
		},
		//1,3 住宅、别墅  2，商铺。  4 车位
		initData(data) {
			this.houseData = [];
			this.storeList = [];
			this.carList = [];
			this.originalHouseData = [];
			this.houseTrue = [];
			this.storeTrue = [];
			this.carTrue = [];
			// console.log("data: " + JSON.stringify(data));
			for (let i in data) {

				// if (i == '1') {
				// 	this.originalHouseData = data[i];
				// 	this.initHouseData(data[i]);
