				// 			this.houseTrue.push(res);
				// 		}
				// 	});
				// }
				// if (i == '2') {
				// 	this.originalStoreData = data[i];
				// 	this.initStoreData(data[i]);
				// 	this.originalStoreData.forEach(res => {
				// 		if (res.buyed == true) {
				// 			this.storeTrue.push(res);
				// 		}
				// 	});
				// }
				// if (i == '3') {
				// 	this.originalHouseData = data[i];
				// 	this.initHouseData(data[i]);
				// 	this.originalHouseData.forEach(res => {
				// 		if (res.buyed == true) {
				// 			this.houseTrue.push(res);
				// 		}
				// 	});
